            Vector2 vector2_3 = vector2List1[0] * 3f + vector2List1[1] * -6f + vector2List1[2] * 3f;
            Vector2 vector2_4 = vector2List1[0] * -1f + vector2List1[1] * 3f + vector2List1[2] * -3f + vector2List1[3];
            List<Vector2> vector2List2 = new List<Vector2>();
            for (float num = 0.0f; (double) num <= 1.0; num += 0.0001f)
            {
              Vector2 vector2_5 = vector2_1 + vector2_2 * num + vector2_3 * (num * num) + vector2_4 * (num * num * num);
              vector2List2.Add(vector2_5);
            }
            ((DrawingHandleBase) handle).DrawPrimitives((DrawPrimitiveTopology) 5, (ReadOnlySpan<Vector2>) vector2List2.ToArray(), Color.Cyan);
          }
        }
      }
    }
  }
